import{_ as a,o as i,c as t,a4 as n}from"./chunks/framework.Cqne-ChA.js";const h=JSON.parse('{"title":"VIM on z/OS","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/VimOnZOS.md","filePath":"Guides/VimOnZOS.md","lastUpdated":1760390954000}'),l={name:"Guides/VimOnZOS.md"};function o(s,e,r,p,u,c){return i(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="vim-on-z-os" tabindex="-1">VIM on z/OS <a class="header-anchor" href="#vim-on-z-os" aria-label="Permalink to &quot;VIM on z/OS&quot;">​</a></h1><h2 id="why-vim" tabindex="-1">Why VIM? <a class="header-anchor" href="#why-vim" aria-label="Permalink to &quot;Why VIM?&quot;">​</a></h2><p>VIM is a popular and powerful text editor that is often used by programmers for writing code. While VIM is available on many different platforms, it can also be used on z/OS.</p><h2 id="how-to-obtain-vim-on-z-os" tabindex="-1">How to obtain VIM on z/OS? <a class="header-anchor" href="#how-to-obtain-vim-on-z-os" aria-label="Permalink to &quot;How to obtain VIM on z/OS?&quot;">​</a></h2><p>To obtain VIM on z/OS, use the <a href="https://zopencommunity.github.io/meta/#/Guides/ThePackageManager" target="_blank" rel="noreferrer">zopen package manager</a> to install it as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen install vim</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Since VIM depends on ncurses, it will automatically download ncurses as a runtime dependency.</p><h2 id="how-to-obtain-alpha-release-of-vim-on-z-os-with-dataset-i-o-support" tabindex="-1">How to obtain Alpha release of VIM on z/OS with Dataset I/O support <a class="header-anchor" href="#how-to-obtain-alpha-release-of-vim-on-z-os-with-dataset-i-o-support" aria-label="Permalink to &quot;How to obtain Alpha release of VIM on z/OS with Dataset I/O support&quot;">​</a></h2><p>To obtain <a href="https://github.com/zopencommunity/vimport/releases/tag/datasetio" target="_blank" rel="noreferrer">VIM on z/OS with dataset I/O support</a>, use the <a href="https://zopencommunity.github.io/meta/#/Guides/ThePackageManager" target="_blank" rel="noreferrer">zopen package manager</a> to install it as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen install vim%datasetio</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>It will automatically download ncurses and libdio as runtime dependencies.</p><h2 id="how-to-use-vim" tabindex="-1">How to use VIM? <a class="header-anchor" href="#how-to-use-vim" aria-label="Permalink to &quot;How to use VIM?&quot;">​</a></h2><p>Now, you can use VIM to edit new or existing files:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vim new.txt # create a new file</span></span>
<span class="line"><span>vim ~/.profile # edit an existing file</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>On z/OS, VIM recognizes <code>IBM-1047</code> and <code>ISO8859-1</code> file tags when you set <code>export _BPK_AUTOCVT=ON</code></p><p>To enable support for a broader range of code pages, use:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export _BPK_AUTOCVT=ALL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>When editing a new or untagged file, VIM will default to tagging it as <code>ISO8859-1</code> (ASCII). You can change this default by setting the <code>_ENCODE_FILE_NEW</code> environment variable. For example, to tag new files as <code>IBM-1047</code>, use:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export _ENCODE_FILE_NEW=IBM-1047</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>For existing files, VIM will retain the original tag, even if the file is untagged.</p><h2 id="improving-your-vim-experience-with-various-tools-and-plugins" tabindex="-1">Improving your VIM experience with various tools and plugins <a class="header-anchor" href="#improving-your-vim-experience-with-various-tools-and-plugins" aria-label="Permalink to &quot;Improving your VIM experience with various tools and plugins&quot;">​</a></h2><h3 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h3><h4 id="cscope" tabindex="-1">Cscope <a class="header-anchor" href="#cscope" aria-label="Permalink to &quot;Cscope&quot;">​</a></h4><p><strong>Cscope</strong> is a tool that allows users to search for symbols, functions, and other code constructs in a codebase. This can be incredibly useful when working with large codebases on z/OS, as it allows users to quickly navigate and find the code they need.</p><p>To use Cscope, first download it using <code>zopen install cscope</code> and then source the .env file as follows: <code>. ./.env</code></p><p>Now, navigate to a codebase. Let&#39;s take the Git source as an example. Since Git is a C-based project, we&#39;ll use Cscope to a cscope database for all of the C source files and headers.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>find . -name &#39;*.c&#39; -o -name &quot;*.h&quot; &gt; cscope.files</span></span>
<span class="line"><span>cscope -b -i cscope.files # Create the cscope db file</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Now, load up VIM from your project root directory. You can now use the <code>:cscope</code> tool to search the references to a definition.</p><p>For example:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:cscope find main all</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Will locate all references to main</p><p>To map the cscope to shortcut keys, the following vim script is recommended: <a href="https://github.com/joe-skb7/cscope-maps/blob/master/plugin/cscope_maps.vim" target="_blank" rel="noreferrer">https://github.com/joe-skb7/cscope-maps/blob/master/plugin/cscope_maps.vim</a>. You can copy and paste it to your .vimrc.</p><h4 id="ctags" tabindex="-1">CTags <a class="header-anchor" href="#ctags" aria-label="Permalink to &quot;CTags&quot;">​</a></h4><p>Another useful tool is <strong>ctags</strong>, which is similar to cscope but operates at a lower level. Ctags generates a list of tags for a codebase, which can then be used by VIM to quickly navigate to specific functions and other code constructs. This can be a huge time-saver when working with complex codebases on z/OS.</p><p>To use CTags, first download it using <code>zopen install ctags</code> and then source the .env file as follows: <code>. ./.env</code></p><p>Now, navigate to a codebase. Let&#39;s take the Git source as an example.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ctags -R . # this will create a tags file in the current dir</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You can now load up VIM on a source file and then place your cursor on a function, variable, or type and use the ctrl-] short-cut to jump to its definition. To jump back, you can use ctrl-t.</p><p>For more details on ctags and cscope, read this lovely tutorial: <a href="https://www.embeddedts.com/blog/tag-jumping-in-a-codebase-using-ctags-and-cscope-in-vim/" target="_blank" rel="noreferrer">https://www.embeddedts.com/blog/tag-jumping-in-a-codebase-using-ctags-and-cscope-in-vim/</a></p><h3 id="plugins" tabindex="-1">Plugins <a class="header-anchor" href="#plugins" aria-label="Permalink to &quot;Plugins&quot;">​</a></h3><h4 id="install-vim-plug" tabindex="-1">Install vim-plug <a class="header-anchor" href="#install-vim-plug" aria-label="Permalink to &quot;Install vim-plug&quot;">​</a></h4><p>vim-plug is a popular plug-in manager for Vim that makes it easy to install and manage plugins.</p><p>Install vim-plug by running the following command:</p><blockquote><p>curl -fLo ~/.vim/autoload/plug.vim --create-dirs <br><a href="https://raw.githubusercontent.com/junegunn/vim-plug/master/plug.vim" target="_blank" rel="noreferrer">https://raw.githubusercontent.com/junegunn/vim-plug/master/plug.vim</a></p></blockquote><p>This command downloads and places the plug.vim file in the ~/.vim/autoload/ directory.</p><h4 id="configure-vim-plug" tabindex="-1">Configure vim-plug <a class="header-anchor" href="#configure-vim-plug" aria-label="Permalink to &quot;Configure vim-plug&quot;">​</a></h4><p>Open your Vim configuration file (~/.vimrc) or create it if it doesn’t exist</p><blockquote><p>vim ~/.vimrc</p></blockquote><p>Add the following lines to your .vimrc to initialize vim-plug and install the vim-gnupg plugin</p><blockquote><p>&quot; Set up vim-plug (plugin manager) <br><br> call plug#begin(&#39;~/.vim/plugged&#39;) <br><br> &quot; Add plugins here<br></p><p>&quot; Initialize plugin system <br> call plug#end()</p></blockquote><p>This configuration tells vim-plug to manage plugins and specifies vim-gnupg as a plugin to be installed</p><h4 id="plugins-for-gpg" tabindex="-1">Plugins for GPG <a class="header-anchor" href="#plugins-for-gpg" aria-label="Permalink to &quot;Plugins for GPG&quot;">​</a></h4><p>Add the following in .vimrc file between plug#begin and plug#end:</p><blockquote><p>&quot; Install the vim-gnupg plugin <br> Plug &#39;jamessan/vim-gnupg&#39;</p></blockquote><h4 id="install-vim-gnupg-plugin" tabindex="-1">Install vim-gnupg Plugin <a class="header-anchor" href="#install-vim-gnupg-plugin" aria-label="Permalink to &quot;Install vim-gnupg Plugin&quot;">​</a></h4><p>After saving the .vimrc file, open Vim and run the following command to install the plugins</p><blockquote><p>:PlugInstall</p></blockquote><p>vim-plug will download and install the vim-gnupg plugin for you</p><h4 id="using-vim-gnupg" tabindex="-1">Using vim-gnupg <a class="header-anchor" href="#using-vim-gnupg" aria-label="Permalink to &quot;Using vim-gnupg&quot;">​</a></h4><p><strong>Encrypting a file:</strong> Open or create a file with a .gpg, .pgp, or .asc extension in Vim: <br></p><blockquote><p>vim secretfile.gpg</p></blockquote><p>When you save the file, vim-gnupg will automatically encrypt it</p><p><strong>Decrypting a File:</strong> Open an encrypted file in Vim by running</p><blockquote><p>vim secretfile.gpg</p></blockquote><h4 id="vim-airline" tabindex="-1">vim-airline <a class="header-anchor" href="#vim-airline" aria-label="Permalink to &quot;vim-airline&quot;">​</a></h4><p>vim-airline is a lightweight status/tabline plugin for Vim. It replaces the standard status line with a more aesthetically pleasing and feature-rich status line. It provides essential information like the current file, line number, file encoding, file type, and Git branch in a minimalistic and visually appealing manner.</p><h4 id="vim-airline-themes" tabindex="-1">vim-airline-themes <a class="header-anchor" href="#vim-airline-themes" aria-label="Permalink to &quot;vim-airline-themes&quot;">​</a></h4><p>vim-airline-themes is a companion plugin to vim-airline that offers a variety of themes to customize the appearance of the status line. This plugin makes it easy to switch themes to match your preferred color scheme or to enhance your coding environment&#39;s visual appeal.</p><p>Add the following in .vimrc file between plug#begin and plug#end:</p><blockquote><p>&quot; Install the airline plugin<br> Plug &#39;vim-airline/vim-airline&#39;<br><br> &quot; Install the airline-themes plugin<br> Plug &#39;vim-airline/vim-airline-themes&#39;</p></blockquote><h4 id="install-vim-airline-vim-airline-themes-plugin" tabindex="-1">Install vim-airline &amp; vim-airline-themes Plugin <a class="header-anchor" href="#install-vim-airline-vim-airline-themes-plugin" aria-label="Permalink to &quot;Install vim-airline &amp; vim-airline-themes Plugin&quot;">​</a></h4><p>After saving the .vimrc file, open Vim and run the following command to install the plugins</p><blockquote><p>:PlugInstall</p></blockquote><p>For more details on Airline and Airline-themes, visit <a href="https://github.com/vim-airline/vim-airline" target="_blank" rel="noreferrer">https://github.com/vim-airline/vim-airline</a> &amp; <a href="https://github.com/vim-airline/vim-airline-themes" target="_blank" rel="noreferrer">https://github.com/vim-airline/vim-airline-themes</a>.</p><h4 id="tagbar" tabindex="-1">Tagbar <a class="header-anchor" href="#tagbar" aria-label="Permalink to &quot;Tagbar&quot;">​</a></h4><p>Tagbar is a source code browsing tool that displays the outline of the code currently open in a Vim window. It uses the ctags utility to generate tags—indexed elements in your code—allowing for efficient and quick navigation. Tagbar’s sidebar acts like a visual table of contents, making it simple to locate specific code segments without scrolling or searching manually.</p><p>Add the following in .vimrc file between plug#begin and plug#end:</p><blockquote><p>&quot; Install the Tagbar plugin<br> Plug &#39;preservim/tagbar&#39;</p></blockquote><h4 id="install-tagbar-plugin" tabindex="-1">Install Tagbar Plugin <a class="header-anchor" href="#install-tagbar-plugin" aria-label="Permalink to &quot;Install Tagbar Plugin&quot;">​</a></h4><p>After saving the .vimrc file, open Vim and run the following command to install the plugins</p><blockquote><p>:PlugInstall</p></blockquote><p>For more details on Tagbar, visit <a href="https://github.com/preservim/tagbar" target="_blank" rel="noreferrer">https://github.com/preservim/tagbar</a>.</p><h4 id="nerdtree" tabindex="-1">NERDTree <a class="header-anchor" href="#nerdtree" aria-label="Permalink to &quot;NERDTree&quot;">​</a></h4><p>In addition to cscope and ctags, VIM users on z/OS may also want to consider using NERDTree, a plugin that allows users to view and navigate the directory structure of a codebase. This can be useful for quickly switching between files and folders, and is especially useful for working with large codebases that have many different directories and files.</p><p>Add the following in .vimrc file between plug#begin and plug#end:</p><blockquote><p>&quot; Install the NERDTree plugin<br> Plug &#39;preservim/nerdtree&#39;</p></blockquote><h4 id="install-nerdtree-plugin" tabindex="-1">Install NERDTree Plugin <a class="header-anchor" href="#install-nerdtree-plugin" aria-label="Permalink to &quot;Install NERDTree Plugin&quot;">​</a></h4><p>After saving the .vimrc file, open Vim and run the following command to install the plugins</p><blockquote><p>:PlugInstall</p></blockquote><p>For more details on NERDTree, visit <a href="https://github.com/preservim/nerdtree" target="_blank" rel="noreferrer">https://github.com/preservim/nerdtree</a>.</p><h4 id="plugins-for-git" tabindex="-1">Plugins for Git <a class="header-anchor" href="#plugins-for-git" aria-label="Permalink to &quot;Plugins for Git&quot;">​</a></h4><h4 id="vim-fugitive" tabindex="-1">vim-fugitive <a class="header-anchor" href="#vim-fugitive" aria-label="Permalink to &quot;vim-fugitive&quot;">​</a></h4><p>To quote <a href="https://github.com/tpope/vim-fugitive?tab=readme-ov-file#fugitivevim" target="_blank" rel="noreferrer">its README</a>:</p><blockquote><p>Fugitive is the premier Vim plugin for Git. Or maybe it&#39;s the premier Git plugin for Vim? Either way, it&#39;s &quot;so awesome, it should be illegal&quot;. That&#39;s why it&#39;s called Fugitive.</p></blockquote><p>This plugin allows VIM users on z/OS to interact with Git repositories directly from within the editor. This can be incredibly useful for managing code changes and collaborating with other developers, as it allows users to easily manage branches, commit changes, and push code to remote repositories.</p><p>Add the following in .vimrc file between plug#begin and plug#end:</p><blockquote><p>&quot; Install the Fugitive plugin<br> Plug &#39;tpope/vim-fugitive&#39;</p></blockquote><h4 id="install-the-fugitive-plugin" tabindex="-1">Install the Fugitive plugin <a class="header-anchor" href="#install-the-fugitive-plugin" aria-label="Permalink to &quot;Install the Fugitive plugin&quot;">​</a></h4><p>After saving the .vimrc file, open Vim and run the following command to install the plugins</p><blockquote><p>:PlugInstall</p></blockquote><p>For more details on vim-fugitive, visit <a href="https://github.com/tpope/vim-fugitive?tab=readme-ov-file#fugitivevim" target="_blank" rel="noreferrer">https://github.com/tpope/vim-fugitive</a>.</p><h4 id="vim-gitgutter" tabindex="-1">vim-gitgutter <a class="header-anchor" href="#vim-gitgutter" aria-label="Permalink to &quot;vim-gitgutter&quot;">​</a></h4><blockquote><p>A Vim plugin which shows a git diff in the sign column. It shows which lines have been added, modified, or removed. You can also preview, stage, and undo individual hunks; and stage partial hunks. The plugin also provides a hunk text object.</p></blockquote><p>Add the following in .vimrc file between plug#begin and plug#end:</p><blockquote><p>&quot; Install the gitgutter plugin <br> Plug &#39;airblade/vim-gitgutter&#39;</p></blockquote><h4 id="install-the-gitgutter-plugin" tabindex="-1">Install the gitgutter plugin <a class="header-anchor" href="#install-the-gitgutter-plugin" aria-label="Permalink to &quot;Install the gitgutter plugin&quot;">​</a></h4><p>After saving the .vimrc file, open Vim and run the following command to install the plugins</p><blockquote><p>:PlugInstall</p></blockquote><p>For more details on vim-gitgutter, visit <a href="https://github.com/airblade/vim-gitgutter" target="_blank" rel="noreferrer">https://github.com/airblade/vim-gitgutter</a>.</p><h4 id="the-complete-example-of-vimrc-file" tabindex="-1">The complete example of .vimrc file <a class="header-anchor" href="#the-complete-example-of-vimrc-file" aria-label="Permalink to &quot;The complete example of .vimrc file&quot;">​</a></h4><blockquote><p>&quot; Set up vim-plug (plugin manager)<br> call plug#begin(&#39;~/.vim/plugged&#39;)<br><br></p><p>&quot; Install the vim-gnupg plugin<br> Plug &#39;jamessan/vim-gnupg&#39;<br><br></p><p>&quot; Install the Tagbar plugin<br> Plug &#39;preservim/tagbar&#39;<br><br></p><p>&quot; Install the NERDTree plugin<br> Plug &#39;preservim/nerdtree&#39;<br><br></p><p>&quot; Install the Fugitive plugin<br> Plug &#39;tpope/vim-fugitive&#39;<br><br></p><p>&quot; Install the gitgutter plugin<br> Plug &#39;airblade/vim-gitgutter&#39;<br><br></p><p>&quot; Install the airline plugin<br> Plug &#39;vim-airline/vim-airline&#39;<br><br></p><p>&quot; Install the airline-themes plugin<br> Plug &#39;vim-airline/vim-airline-themes&#39;<br><br></p><p>&quot; Initialize plugin system<br> call plug#end()</p></blockquote>`,111)])])}const d=a(l,[["render",o]]);export{h as __pageData,d as default};
